// Grouper les produits par email gérant pour un seul email par boutique
const produits = $input.all().map(i => i.json);

const grouped = {};
produits.forEach(p => {
  const email = p.email_gerant || 'gerant@boutique.re';
  if (!grouped[email]) grouped[email] = [];
  grouped[email].push(p);
});

return Object.entries(grouped).map(([email, produits]) => ({
  json: {
    email,
    produits,
    nbProduits: produits.length,
    produitsEnRupture: produits.filter(p => p.stock_actuel === 0).length,
    tableau: produits.map(p => 
      `<tr style="${p.stock_actuel === 0 ? 'background:#fff5f5' : ''}">
        <td style="padding:8px;border:1px solid #e0e0e0">${p.nom}</td>
        <td style="padding:8px;border:1px solid #e0e0e0">${p.categorie || '-'}</td>
        <td style="padding:8px;border:1px solid #e0e0e0;${p.stock_actuel === 0 ? 'color:red;font-weight:bold' : 'color:orange'}">${p.stock_actuel === 0 ? '⛔ RUPTURE' : '⚠️ ' + p.stock_actuel}</td>
        <td style="padding:8px;border:1px solid #e0e0e0;color:#888">${p.seuil_alerte}</td>
      </tr>`
    ).join('')
  }
}));
